-- Name: view_revenue_analytics; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.view_revenue_analytics AS
 SELECT (o.created_at)::date AS report_date,
    (EXTRACT(hour FROM o.created_at))::integer AS report_hour,
    o.id AS order_id,
    o.payment_method,
    od.product_id,
    od.product_title,
    p.category_id,
    od.category_name,
    od.quantity AS total_quantity_sold,
    (od.price * od.quantity) AS total_revenue
   FROM (((public.order_detail od
     JOIN public.orders o ON ((od.order_id = o.id)))
     JOIN public.invoice i ON ((o.id = i.order_id)))
     JOIN public.product p ON ((od.product_id = p.id)))
  WHERE (((o.status)::text = 'COMPLETED'::text) AND ((i.status)::text = 'PAID'::text));


ALTER VIEW public.view_revenue_analytics OWNER TO postgres;

